-- Migration 012d: Implementation Plans — Batch D (IDs 66-75)
-- ─────────────────────────────────────────────────────────────────────────────────────
BEGIN;

INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    66,
    'TIA 2.0 reform restructures the Technology Innovation Agency from a generalist bridging funder into a sector-focused co-investment vehicle targeting R1 billion annual deal flow by 2028. DSI will lead a governance overhaul to introduce independent investment committee members drawn from VC and corporate venture communities, three sector desks (agri-tech, health-tech, green tech) each with a dedicated sector lead, and a co-investment framework that requires private VC participation for all deals above R10 million. Decision timelines will be capped at 90 days from application to term sheet. Performance will be benchmarked against SIFIN (Singapore), Enterprise Ireland, and the UK''s Innovate UK.',
    '[
      {"step":1,"description":"DSI commissions independent operational review of TIA deal flow, decision timelines, and portfolio performance 2018-2024; benchmark against Enterprise Ireland and Innovate UK on time-to-decision, co-investment ratios, and portfolio failure rates","timeline":"Q1-Q2 2025","responsible_party":"Department of Science and Innovation (DSI) / external consultant"},
      {"step":2,"description":"Amend TIA Board composition via ministerial determination under the Technology Innovation Agency Act 26 of 2008: add five independent investment professionals with VC or corporate venture experience; introduce a nine-member investment committee with a minimum three-deal quorum requirement and 90-day decision deadline","timeline":"Q2-Q3 2025","responsible_party":"DSI / TIA Board"},
      {"step":3,"description":"Establish three sector desks — agri-tech, health-tech, green tech — each staffed with a sector lead (minimum 10 years industry experience), two deal managers, and one commercialisation specialist; publish sector investment theses aligned with DSI priorities and SEDA ecosystem needs","timeline":"Q3-Q4 2025","responsible_party":"TIA CEO / DSI"},
      {"step":4,"description":"Launch co-investment framework: TIA provides up to 50% of funding for deals above R10 million, contingent on matching contribution from accredited VC partner, corporate venture fund, or DFI; publish list of accredited co-investors; set portfolio target of R500 million co-invested by 2027","timeline":"Q4 2025","responsible_party":"TIA / National Treasury (fiscal envelope sign-off)"},
      {"step":5,"description":"Increase TIA parliamentary appropriation from R700 million to R1.2 billion per year over MTEF 2026-2028 and introduce a revolving fund mechanism so equity exits and royalty receipts are retained for reinvestment rather than returned to Treasury","timeline":"MTEF 2026/27 submission (Q3 2025)","responsible_party":"DSI / National Treasury"},
      {"step":6,"description":"Establish annual TIA innovation portfolio report tabled in Parliament covering deal flow volumes, sector distribution, co-investment ratios, portfolio company employment, and revenue; report reviewed by Portfolio Committee on Higher Education, Science and Innovation","timeline":"Annual from Q2 2026","responsible_party":"TIA / DSI"}
    ]',
    '18 months to governance overhaul and sector desk launch (Q1 2025 – Q2 2026); R1 billion annual deal flow target by 2028',
    'Additional parliamentary appropriation of R500 million/year above current baseline; co-investment framework draws in matching private capital; total portfolio leverage target 1.5x public funds',
    'Technology Innovation Agency Act 26 of 2008 amendment required to revise board composition and introduce revolving fund mechanism; Public Finance Management Act 1 of 1999 implications for retained equity proceeds require National Treasury approval',
    'Primary amendment needed to TIA Act Section 7 (Board composition) and Section 21 (Funds) to allow revolving equity reinvestment. The Section 21 amendment requires a money bill process under Section 77 of the Constitution. DSI can proceed with sector desk restructuring and co-investment framework by ministerial directive pending legislative amendment.',
    'Broad support across DSI, DTIC, and the presidency''s investment drive. The DA and EFF have both criticised TIA''s slow deal flow in portfolio committee hearings. Industry (SAVCA — SA Venture Capital and Private Equity Association) supports the co-investment model. Resistance expected from existing TIA management over governance overhaul and accountability mechanisms.',
    'Enterprise Ireland''s co-investment fund model (EUR 175 million, 2023) requires 1:1 private matching and has achieved sub-60-day decision timelines. Innovate UK''s Investor Partnerships programme co-invests with accredited VC firms on SBRI contracts — a direct template for TIA''s accreditation framework. Singapore''s SIFIN (Startup SG) provides sector-desk specialisation benchmarks relevant to agri-tech and health-tech verticals.'
);

INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    67,
    'The IPR-PFRD Act (Intellectual Property Rights from Publicly Financed Research and Development Act 51 of 2008) is the South African equivalent of the US Bayh-Dole Act, requiring public research institutions to disclose, protect, and commercialise IP arising from state-funded R&D. NIPMO (National Intellectual Property Management Office) under DSIT administers the act but is widely criticised for slow IP disclosure processing times (averaging 18 months), excessive approval requirements for low-value licensing, and the absence of a searchable national IP register. Reform targets: 90-day disclosure-to-protection decision, automatic licensing authority for institutions on IP valued below R5 million, and a live central IP register accessible to startups and industry.',
    '[
      {"step":1,"description":"DSIT commissions a compliance and performance audit of NIPMO: map all IP disclosure filings 2010-2024, measure time from disclosure to protection decision, calculate royalty revenues generated, and identify IP abandoned due to process delays; benchmark against Bayh-Dole reporting metrics from US AUTM annual survey","timeline":"Q1-Q2 2025","responsible_party":"Department of Science, Innovation and Technology (DSIT) / NIPMO"},
      {"step":2,"description":"Draft amendments to IPR-PFRD Act Sections 5 and 8: introduce a 90-day statutory decision deadline for NIPMO IP protection determinations; create a tiered authority model — institutions may directly license IP valued below R5 million to any licensee without NIPMO approval, provided they report quarterly; NIPMO approval retained for exclusive licences and IP above R5 million threshold","timeline":"Q2-Q4 2025","responsible_party":"DSIT Legal Services / NIPMO / dtic (CIPC)"},
      {"step":3,"description":"Establish a National IP Register: CIPC to develop and host a publicly accessible database of publicly-funded IP assets available for licensing, with standardised IP disclosure summaries, technology readiness levels, and institution contact details; integrate with NIPMO''s case management system","timeline":"Q3 2025-Q2 2026","responsible_party":"CIPC / NIPMO / DSIT"},
      {"step":4,"description":"Introduce startup fast-track licensing pathway: publicly-funded institutions may offer 3-year exclusive licences to registered startups (CIPC registration under 3 years, turnover below R10 million) at minimal upfront royalty in exchange for equity or milestone-based payments; NIPMO to develop standard licence template","timeline":"Q4 2025","responsible_party":"NIPMO / DSIT / TIA"},
      {"step":5,"description":"Increase NIPMO staffing and operational budget: recruit five additional IP commercialisation specialists with industry or patent attorney backgrounds; automate IP disclosure workflow using WIPO''s IP management software (IPAS); target 90-day processing for 80% of new disclosures by end 2026","timeline":"Q1-Q4 2026","responsible_party":"NIPMO / DSIT Human Resources"},
      {"step":6,"description":"Table IPR-PFRD Amendment Bill in Parliament; gazette regulations under the amended act specifying disclosure timelines, tiered authority thresholds, and IP register publication requirements; annual report to Portfolio Committee on Higher Education, Science and Innovation on disclosure volumes, commercialisation revenues, and technology transfer outcomes","timeline":"Bill tabled Q1 2026; enacted Q3 2026","responsible_party":"DSIT / Parliament"}
    ]',
    '24 months from audit to enacted amendments (Q1 2025 – Q1 2027); National IP Register live by Q2 2026',
    'NIPMO operational budget increase: R30 million/year (staff and IT); CIPC IP Register development: R15 million capital; total public cost ~R75 million over 3 years; expected royalty revenue uplift R200-400 million/year as commercialisation accelerates',
    'IPR-PFRD Act 51 of 2008 amendment required for tiered authority model and statutory timelines; CIPC Act 71 of 2008 may require amendment or ministerial regulation to mandate IP register hosting',
    'The IPR-PFRD Amendment Bill requires introduction by the Minister of Science, Innovation and Technology and must pass through the Portfolio Committee on Higher Education, Science and Innovation. The tiered licensing threshold (R5 million) and startup fast-track provisions are likely to attract public interest submissions from universities and the SAVCA. No money bill implications — NIPMO budget increase is handled through the annual appropriation.',
    'Supported by university technology transfer offices (UCT, Wits, UKZN), SAVCA, and SACCI. Some universities oppose a more prescriptive NIPMO regime and prefer greater institutional autonomy — the tiered authority model is designed to address this tension. DSIT has included IPR-PFRD reform in the STI Decadal Plan implementation schedule.',
    'The US Bayh-Dole Act (1980) and its implementing regulations (37 CFR Part 401) provide the foundational model; AUTM surveys show US universities generated $3.9 billion in licensing revenue in 2022 from Bayh-Dole licences. Canada''s IP Strategy (2018) introduced a similar tiered licensing authority for federal labs. Australia''s NISA (National IP and Science Agenda, 2015) created an online IP register for publicly-funded research — a direct model for the CIPC/NIPMO register.'
);

INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    68,
    'The SA Innovation Fund was established in 2019 by DSIT as a blended finance vehicle to bridge the gap between NRF grants and commercial VC for deep-tech startups. Its pilot phase (2019-2024) disbursed R1.5 billion across 40+ companies in AI, biotech, advanced manufacturing, and clean energy. Scale-up to R5 billion over 2025-2030 requires a formal co-investment framework with international DFIs — IFC, EIB, and the KfW DEG — private VC firms through a fund-of-funds structure, and corporate venture partnerships with JSE-listed corporates. The Fund must also establish a performance management system to track portfolio company revenue, employment, and export growth.',
    '[
      {"step":1,"description":"DSIT and National Treasury commission an independent evaluation of the Innovation Fund pilot phase 2019-2024: assess portfolio company survival rates, revenue growth, employment creation, and technology commercialisation outcomes; benchmark against IFC Venture Capital Fund and EIB Innovation Finance programme","timeline":"Q1-Q2 2025","responsible_party":"DSIT / National Treasury / independent evaluator"},
      {"step":2,"description":"Negotiate co-investment framework agreements with IFC (target R800 million commitment), EIB (R600 million via SA-EU Green Deal envelope), and KfW DEG (R400 million); structure as parallel co-investment vehicles with aligned investment criteria and shared portfolio reporting standards","timeline":"Q2-Q4 2025","responsible_party":"DSIT / National Treasury / dtic (IDC as co-manager)"},
      {"step":3,"description":"Establish a Fund-of-Funds structure for private VC participation: Innovation Fund allocates R500 million to anchor investments in 5-8 accredited SA-based VC funds (managed by SAVCA-registered managers) with a minimum 2x match requirement from private LPs; publish VC fund accreditation criteria","timeline":"Q3-Q4 2025","responsible_party":"SA Innovation Fund / SAVCA"},
      {"step":4,"description":"Launch corporate venture partnership programme: offer JSE-listed corporates co-investment rights in Innovation Fund portfolio companies in exchange for corporate venture commitments of R100 million or above; target 5 anchor corporates (Naspers/Prosus, Standard Bank, FirstRand, Anglo American, Vodacom) by 2026","timeline":"Q4 2025-Q2 2026","responsible_party":"SA Innovation Fund / DSIT / JSE"},
      {"step":5,"description":"Establish a portfolio performance management system: standardised quarterly reporting by portfolio companies on revenue, headcount, export revenues, and R&D expenditure; public annual portfolio report; DSIT submits innovation fund performance dashboard to Parliament annually","timeline":"Q3 2025 (system), Q1 2026 (first annual report)","responsible_party":"SA Innovation Fund / DSIT"},
      {"step":6,"description":"Increase parliamentary appropriation to Innovation Fund to R700 million/year over 2026-2030 MTEF cycle to achieve R5 billion total commitment; structure appropriation as a revolving fund with equity exit proceeds retained for reinvestment; obtain National Treasury approval under PFMA Section 16 for revolving fund status","timeline":"MTEF 2026/27 submission","responsible_party":"DSIT / National Treasury"},
      {"step":7,"description":"Launch third deep-tech cohort targeting health-tech, climate-tech, and agri-tech: 20 new companies per year with average ticket size of R35 million; require each portfolio company to engage with a CSIR or NRF research partner; track 5-year commercialisation milestones","timeline":"Q1 2026","responsible_party":"SA Innovation Fund / CSIR / NRF"}
    ]',
    '5-year scale-up 2025-2030; DFI agreements by Q4 2025; R5 billion fully committed by 2030',
    'Government contribution R700 million/year (R3.5 billion over 5 years); DFI co-investment R1.8 billion; private VC fund-of-funds R1 billion; corporate venture R500 million; total capitalisation R6.8 billion with 1.9x leverage on public funds',
    'PFMA Schedule 3A amendment to give Innovation Fund revolving fund status; potential amendment to IDC Act if IDC acts as co-manager; no new primary legislation required for DFI co-investment framework (governed by bilateral agreements)',
    'The revolving fund mechanism under PFMA requires National Treasury approval via a Section 16 determination — this is an administrative process not requiring parliamentary legislation. The MTEF budget increase requires Treasury approval and Cabinet sign-off. DFI co-investment agreements are executive instruments signed by DSIT/dtic and do not require parliamentary ratification.',
    'Broad support in the GNU economic cluster, including DA (pro-private sector co-investment) and ANC (job creation mandate). IDC and DBSA both have interest in co-managing the scale-up vehicle. The fund-of-funds structure will attract scrutiny from the Portfolio Committee on Higher Education, Science and Innovation regarding fund manager selection transparency and BEE compliance.',
    'IFC''s Venture Capital fund-of-funds model (MENA and Sub-Saharan Africa) has deployed over $1.5 billion in emerging market VC, providing a co-investment framework template. EIB''s InnovFin programme (EUR 24 billion, 2014-2020) used blended finance to crowd in private R&D investment across EU member states at 4:1 leverage. Israel''s Yozma programme (1993) used government anchor investment in VC funds to seed a domestic VC industry — SA''s fund-of-funds structure replicates this approach.'
);

INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    69,
    'The STI Decadal Plan 2022-2032 (gazetted by DSIT) sets ambitious targets — 1.5% of GDP in gross R&D expenditure (GERD), 100 PhD graduates per million population, 50 deep-tech startup listings per year — but lacks a funded implementation schedule, annual milestones, and parliamentary accountability mechanisms. Without budget lines tied to targets the plan remains aspirational. Implementation requires three components: an annual funded implementation report tabled in Parliament, MTEF budget allocations explicitly referenced to Decadal Plan targets, and a STI Investment Council chaired by the Presidency to coordinate cross-departmental budget commitments.',
    '[
      {"step":1,"description":"DSIT drafts an Annual STI Implementation Framework (ASIF): a standardised template for annual reporting on Decadal Plan targets covering GERD as % GDP (source: Stats SA R&D Survey), PhD graduate numbers (source: DHET), patent filings (source: CIPC/WIPO), and deep-tech startup registrations (source: TIA/Innovation Fund); establish baseline metrics from 2022 data","timeline":"Q1-Q2 2025","responsible_party":"Department of Science, Innovation and Technology (DSIT) / Stats SA"},
      {"step":2,"description":"Table the first Annual STI Implementation Report in Parliament by Q2 2025: present 2024 actual performance against Decadal Plan targets; identify underfunded programmes; propose corrective budget reallocations; refer to Portfolio Committee on Higher Education, Science and Innovation for review","timeline":"Q2 2025","responsible_party":"Minister of Science, Innovation and Technology / DSIT"},
      {"step":3,"description":"Establish a STI Investment Council under the Presidency''s Economic Cluster: chaired by Deputy President or designated Presidency official; members include Ministers of Finance, Science and Innovation, Trade and Industry, Education, and Health; mandate to approve cross-departmental STI budget allocations aligned to Decadal Plan targets annually","timeline":"Q3 2025","responsible_party":"The Presidency / DSIT"},
      {"step":4,"description":"Negotiate MTEF budget programme tags with National Treasury: each Decadal Plan target receives a Budget Programme Structure code so that annual budget votes for DSIT, DHET, TIA, NRF, and CSIR explicitly reference Decadal Plan milestones; Treasury''s ENE (Estimates of National Expenditure) to include a STI Decadal Plan annex from 2026/27","timeline":"Q3-Q4 2025 (for 2026/27 MTEF)","responsible_party":"DSIT / National Treasury"},
      {"step":5,"description":"Commission a mid-term review of the Decadal Plan in 2027: independent panel (ASSAF, NSTF, ASSAf, international peer reviewers) assesses progress, identifies bottlenecks, and recommends target revisions for the 2027-2032 second half; review findings tabled in Parliament and published publicly","timeline":"2027","responsible_party":"DSIT / ASSAF / NSTF"},
      {"step":6,"description":"Establish a public STI Dashboard (hosted on DSIT website) with quarterly-updated indicators: GERD, patent filings, PhD completions, innovation fund disbursements, TIA deal flow, and deep-tech export revenues; integrate with Stats SA''s R&D Survey data release cycle","timeline":"Q4 2025","responsible_party":"DSIT / Stats SA / CSIR (data infrastructure)"},
      {"step":7,"description":"Anchor Decadal Plan in the national budget framework: DSIT and National Treasury to jointly publish a STI Fiscal Framework alongside the Medium Term Budget Policy Statement each October, detailing public R&D spend by department, tax incentive take-up (Section 11D), and projected GERD trajectory","timeline":"October 2025 (first publication)","responsible_party":"DSIT / National Treasury"}
    ]',
    'Annual reporting cycle from Q2 2025; MTEF budget tagging from 2026/27; mid-term review 2027; full plan horizon to 2032',
    'Institutional setup cost R5-10 million (dashboard, council secretariat); primary cost is the funded programme commitments required to meet targets — estimated R8-12 billion incremental R&D spend over 10 years to reach 1.5% GERD target (current GERD approximately 0.6% GDP)',
    'No new primary legislation required; STI Investment Council established by Presidential proclamation; Annual Implementation Report is an executive accountability mechanism; MTEF budget tagging is an administrative National Treasury reform',
    'The Annual Implementation Report tabled in Parliament operates under existing parliamentary accountability rules — the Minister tables it as a departmental report and it is referred to the Portfolio Committee. No statutory obligation to table currently exists; DSIT can commit to doing so administratively. A binding obligation requires a ministerial directive or amendment to the Technology Innovation Agency Act or a standalone STI Reporting Act.',
    'Broad support across DSIT, DHET, and SETA system. National Treasury has historically resisted earmarked budget tagging as it constrains fiscal flexibility, but the STI Fiscal Framework proposal (alongside MTBPS) is designed to address this without formal earmarking. Universities and the NSTF have publicly advocated for funded implementation since the Decadal Plan was gazetted.',
    'Finland''s Research and Innovation Council (chaired by the Prime Minister) provides a direct model for the STI Investment Council — it has driven Finland''s R&D spend to 2.9% of GDP through coordinated cross-ministerial commitment. South Korea''s National Science and Technology Council coordinates the Five-Year Science and Technology Basic Plan with explicit budget allocations across ministries. The EU''s ERA (European Research Area) targets framework uses a structured indicator dashboard — the basis for the proposed DSIT public STI dashboard.'
);

INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    70,
    'South Africa holds a globally significant green hydrogen advantage: abundant renewable energy potential (Northern Cape solar irradiance, coastal wind), platinum group metal (PGM) reserves critical for electrolyser catalysts and fuel cells, and established port infrastructure at Saldanha Bay and Boegoebaai. The SA Hydrogen Society Roadmap (DMRE, 2021) targets 10 GW electrolyser capacity by 2035 but early demonstration projects remain in feasibility stage. A coordinated R15 billion R&D and demonstration programme over 10 years — jointly managed by DMRE, DSIT, and IDC — is needed to move from roadmap to investable pipeline, certify green hydrogen production, and position SA for EU hydrogen import demand post-2030.',
    '[
      {"step":1,"description":"DMRE, DSIT, and IDC establish a Green Hydrogen Programme Office (GHPO) with a dedicated programme director and secretariat; mandate the GHPO to manage the R15 billion portfolio, coordinate regulatory approvals, and report quarterly to an inter-ministerial steering committee chaired by the Presidency; align GHPO structure with the Just Energy Transition Investment Plan (JET-IP) hydrogen workstream","timeline":"Q1-Q2 2025","responsible_party":"DMRE / DSIT / IDC / The Presidency"},
      {"step":2,"description":"Unlock the three anchor demonstration projects: Boegoebaai Port Industrial Zone (Hive Energy / Envision partnership, target 1 GW electrolyser, green ammonia export), Saldanha Bay H2Global project (Power-to-X, offshore wind link), and the Limpopo Platinum Corridor (hydrogen for PGM refining and heavy transport fuel cell fleet); GHPO provides R&D co-funding of up to 30% of project development costs and fast-tracks environmental authorisations through DFFE''s One Environmental System","timeline":"Q2 2025-Q4 2026","responsible_party":"GHPO / DMRE / DFFE / participating private developers"},
      {"step":3,"description":"Launch a competitive Green Hydrogen Innovation Fund: R3 billion over 5 years for electrolyser localisation R&D (build on HySA — Hydrogen South Africa programme at CSIR/NWU/UCT), green ammonia synthesis optimisation, hydrogen storage materials, and PEM fuel cell manufacturing scale-up; fund through a 50/50 split between DSIT (parliamentary appropriation) and IDC (concessional loans to industry R&D partners)","timeline":"Q3 2025 (fund design), Q1 2026 (first call for proposals)","responsible_party":"DSIT / IDC / HySA (CSIR)"},
      {"step":4,"description":"Develop the green hydrogen certification and standards framework: SABS and SANAS to develop SA-specific green hydrogen certification aligned to EU''s delegated regulation on hydrogen (Delegated Regulation 2023/1184) and the International Partnership for Hydrogen and Fuel Cells in the Economy (IPHE) methodology; this is essential for EU export market access post-2030","timeline":"Q2 2025-Q4 2026","responsible_party":"SABS / SANAS / DMRE / dtic"},
      {"step":5,"description":"Negotiate bilateral hydrogen offtake framework agreements with Germany (H2Global mechanism, EUR 900 million allocated for non-EU green hydrogen imports) and the Netherlands (Rotterdam hydrogen import terminal, operational 2025); SA government provides sovereign backing for minimum volume commitments from demonstration projects to underwrite private investment","timeline":"Q2-Q4 2025","responsible_party":"DMRE / DIRCO / dtic"},
      {"step":6,"description":"Integrate green hydrogen infrastructure into the national spatial development framework: designate Boegoebaai and Saldanha Bay as Special Economic Zones with hydrogen-specific investment incentives under the SEZ Act; fast-track NERSA licensing for dedicated renewable energy supply to electrolysers; develop a hydrogen pipeline corridor feasibility study for the Western Cape-Northern Cape axis","timeline":"Q3 2025-Q2 2027","responsible_party":"DTIC (SEZ division) / NERSA / DMRE / Transnet"},
      {"step":7,"description":"Annual Green Hydrogen Programme Report to Parliament: GHPO publishes electrolyser capacity installed, R&D milestones achieved, international agreements concluded, and projected export revenue pipeline; report reviewed by Portfolio Committee on Mineral Resources and Energy and Portfolio Committee on Trade, Industry and Competition","timeline":"Annual from Q2 2026","responsible_party":"GHPO / DMRE"}
    ]',
    '10-year programme 2025-2035; demonstration projects operational by 2028; 10 GW electrolyser target by 2035; EU export market access from 2030',
    'Total public R&D programme: R15 billion over 10 years (DSIT R7 billion, DMRE R4 billion, IDC R4 billion concessional finance); private sector co-investment target R45 billion; total programme R60 billion; JET-IP hydrogen workstream allocates R20 billion from international climate finance (EU, Germany, UK, US)',
    'No new primary legislation required; SEZ Act 16 of 2014 and Special Economic Zones Regulations provide framework for hydrogen SEZ designations; NERSA licensing authority under Electricity Regulation Act covers dedicated renewable supply; PFMA governs GHPO fund management under IDC as implementing agent',
    'SEZ designation for Boegoebaai and Saldanha Bay requires a ministerial determination by the Minister of Trade, Industry and Competition under SEZ Act Section 23 — an administrative process. NERSA dedicated renewable energy licences are issued under ERA Section 34. The sovereign offtake commitment backing for international agreements requires Cabinet approval but not parliamentary ratification.',
    'Strong ANC policy commitment — green hydrogen is a Just Energy Transition priority and an economic development narrative. GNU partners (DA, IFP) support on investment and jobs grounds. The main political risk is coordination failure across DMRE, DSIT, dtic, and DFFE — the GHPO is designed to address this. Environmental groups broadly support green hydrogen but will scrutinise water use in water-stressed regions (desalination requirement at Boegoebaai).',
    'Germany''s National Hydrogen Strategy (2020, updated 2023) committed EUR 9 billion in public R&D and infrastructure, achieved 650 MW electrolyser capacity by 2024, and is the template for SA''s programme scale and structure. Chile''s Green Hydrogen Action Plan targets 5 GW electrolysers by 2030 using Atacama solar — directly comparable to SA''s Northern Cape advantage. Morocco''s NOUR and green hydrogen programme (partnered with Germany via H2Global) is the nearest African comparator and demonstrates bilateral offtake feasibility.'
);

INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    71,
    'The CSIR (Council for Scientific and Industrial Research), with 3,000+ researchers and a R5 billion annual budget, is SA''s primary applied research and technology development institution. Its current funding model — approximately 60% parliamentary allocation, 40% contract research — limits its ability to pursue long-horizon foundational digital research. A 10-year Foundational Digital Capabilities Programme covering AI/ML, cybersecurity, quantum computing, and satellite communications requires structural funding reform: a co-funded model with industry partners, international research programmes (CERN, EU Horizon Europe, ITU), and a dedicated endowment fund to sustain multi-year research commitments beyond the annual MTEF cycle.',
    '[
      {"step":1,"description":"CSIR and DSIT commission a strategic positioning review: assess CSIR''s current AI/ML, cybersecurity, quantum, and satellite research capacity against global benchmarks (Fraunhofer, TNO, CSIRO); identify critical capability gaps; map existing international partnerships; produce a 10-year Digital Capabilities Roadmap with costed programme streams","timeline":"Q1-Q2 2025","responsible_party":"CSIR / DSIT / external advisory panel"},
      {"step":2,"description":"Negotiate CSIR participation in EU Horizon Europe (2025-2027 work programme) as an Associated Country partner: DSIT to lead intergovernmental negotiations with the European Commission for SA-EU Science and Technology Agreement update; target participation in Digital, Industry and Space cluster calls worth EUR 100 million over 3 years","timeline":"Q2-Q4 2025","responsible_party":"DSIT / DIRCO / CSIR"},
      {"step":3,"description":"Establish a CSIR Digital Endowment Fund: R2 billion capitalised over 5 years (R500 million DSIT parliamentary allocation, R500 million CSIR retained surpluses, R1 billion from private sector industry partnerships); fund governed by independent investment committee; endowment income used to fund 5-10 year research programmes insulated from annual MTEF cycles","timeline":"Q3 2025-Q4 2026","responsible_party":"CSIR / DSIT / National Treasury (PFMA approval)"},
      {"step":4,"description":"Launch industry co-funding partnerships: negotiate 5-year research agreements with minimum R50 million commitment from each of 10 anchor corporates in sectors aligned to CSIR digital focus areas — financial services (cybersecurity: Standard Bank, FirstRand), telecoms (satellite/5G: MTN, Vodacom), mining (AI/automation: Anglo, Sibanye), and government (quantum: SAPS, SARS); structure as CSIR-led research consortia","timeline":"Q4 2025-Q2 2026","responsible_party":"CSIR CEO / DSIT"},
      {"step":5,"description":"Establish quantum computing research node: partner with IBM (IBM Quantum Network), Google Quantum AI, or IQM to access cloud quantum computing for CSIR researchers; train 50 CSIR quantum researchers by 2028; target two quantum algorithm patents relevant to logistics optimisation and cryptography per year from 2027","timeline":"Q1 2026","responsible_party":"CSIR (quantum research group) / DSIT"},
      {"step":6,"description":"Develop a CSIR-led National Cybersecurity Research Centre: joint venture with SITA (State Information Technology Agency), the Financial Sector Conduct Authority, and three South African universities (Wits, UCT, UNISA); focus on critical infrastructure protection, AI-driven threat detection, and cryptography for financial services; annual threat intelligence report published","timeline":"Q2 2026","responsible_party":"CSIR / SITA / FSCA"},
      {"step":7,"description":"Annual CSIR Digital Programme Report to Parliament: publish research outputs (patents, publications, technology transfers, spin-outs), international collaboration outcomes, industry co-funding receipts, and commercialisation revenues; table in Portfolio Committee on Higher Education, Science and Innovation; include third-party impact assessment every three years","timeline":"Annual from Q2 2026","responsible_party":"CSIR / DSIT"}
    ]',
    '10-year programme 2025-2035; endowment fund capitalised by 2030; EU Horizon participation from 2026 work programme; quantum research node operational 2026',
    'Government endowment contribution R500 million over 5 years (above current parliamentary baseline); industry co-funding target R1.5 billion over 10 years; EU Horizon receipts R500 million over 5 years; total additional programme funding R2.5 billion above current CSIR budget',
    'PFMA Schedule 3A amendment may be required if endowment fund is structured as a separate juristic entity; CSIR Act 46 of 1988 amendment may be needed to allow endowment fund structure and expanded revenue retention; international research agreements (EU Horizon, CERN) governed by DSIT Science and Technology Agreement instruments',
    'The CSIR endowment fund structure requires National Treasury approval under PFMA Section 16 for retained surplus investment. If established as a subsidiary of CSIR, this requires a CSIR Act amendment — a minor technical bill within the competence of the Portfolio Committee on Higher Education, Science and Innovation. EU Horizon SA associated country status requires a government-to-government agreement under DSIT''s mandate.',
    'DSIT and CSIR leadership strongly support the co-funding model — it reduces dependence on parliamentary allocations subject to fiscal consolidation. Industry partners have demonstrated appetite through existing CSIR contract research. The endowment fund structure will require careful National Treasury engagement on PFMA implications. Opposition parties are supportive of international research collaboration (EU Horizon, CERN) as a signal of SA''s scientific credibility.',
    'Germany''s Fraunhofer Society (28,000 researchers, EUR 3 billion budget) operates on a one-third public, two-thirds contract model — the closest global comparator to the CSIR''s desired funding structure. Australia''s CSIRO co-funded R&D model with industry consortia (Mining3, Food Agility) provides a direct template for sector-specific partnership structures. The Netherlands'' TNO operates a digital endowment model with a EUR 400 million strategic fund — a direct reference for the CSIR Digital Endowment Fund design.'
);

INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    72,
    'The National Research Foundation (NRF) funds approximately 30,000 postgraduate students annually through its bursary and scholarship programmes, including the NRF Freestanding, Innovation, and Scarce Skills Doctoral Scholarships. PhD bursary values (R80,000–R120,000 per year) have not kept pace with inflation and are insufficient for living costs in major university cities, contributing to high postgraduate dropout rates, delays in PhD completion, and an inability to compete with Australian, UK, and German scholarship values for South African graduate talent. Industry co-funding partnerships and a skills market matching platform would double effective output by increasing both bursary values and alignment between funded research and industry skills needs.',
    '[
      {"step":1,"description":"NRF and DHET commission a postgraduate funding adequacy review: survey 500 NRF-funded PhD students on living costs, supplementary employment, and financial stress; compare NRF bursary values against Australian Research Council (AUD 32,000/year), DAAD Germany (EUR 1,200/month), and UK UKRI stipends (GBP 19,000/year); quantify the funding gap and its impact on completion rates and time-to-degree","timeline":"Q1-Q2 2025","responsible_party":"NRF / DHET / independent survey firm"},
      {"step":2,"description":"Increase NRF Doctoral Scholarship values by 40% in the 2026/27 MTEF submission: PhD bursaries from R120,000 to R168,000/year; Masters bursaries from R80,000 to R112,000/year; index future values to CPI; submit to National Treasury with an economic modelling report on the return on investment from PhD graduates in the innovation economy","timeline":"Q3-Q4 2025 (MTEF submission)","responsible_party":"NRF / DHET / National Treasury"},
      {"step":3,"description":"Launch the NRF Industry Co-funding Partnership Programme: invite industry sectors to co-fund doctoral bursaries in priority research areas — mining sector (Minerals Council) for geoscience and metallurgy, pharmaceutical sector (PIASA) for biochemistry and pharmacology, fintech sector (FSCA) for data science, energy sector (SAPVIA/SAWEA) for electrical engineering; industry co-funder contributes 50% of bursary value in exchange for non-exclusive IP licensing rights and first-refusal internship offers","timeline":"Q4 2025-Q2 2026","responsible_party":"NRF / DSI / industry partners"},
      {"step":4,"description":"Develop the NRF Skills Market Platform: a digital matching platform (SARS-verified company profiles, NRF-registered student profiles) that connects NRF-funded postgraduate students with industry internship opportunities, co-funded bursary positions, and postdoctoral fellowships; integrate with TIA''s startup network for deep-tech placement; target 2,000 industry-student matches per year by 2027","timeline":"Q2-Q4 2025 (platform development), Q1 2026 (launch)","responsible_party":"NRF / DHET (digital infrastructure)"},
      {"step":5,"description":"Establish NRF Postdoctoral Industrial Fellowship programme: 100 two-year fellowships per year for PhD graduates to work in industry (minimum 6 months in company, 18 months at university research group linked to company project); fellowship value R250,000/year split NRF/industry 50/50; target sectors: advanced manufacturing, biosciences, fintech, and clean energy","timeline":"Q3 2025 (design), Q1 2026 (first cohort)","responsible_party":"NRF / industry partners / Technology Innovation Agency"},
      {"step":6,"description":"Reform NRF bursary administration: migrate to a digital application and disbursement system (current system is largely paper-based); introduce a single application portal for all NRF postgraduate funding streams; reduce processing time from 9 months to 3 months; issue bursary confirmation letters by April each year for the following academic year","timeline":"Q2-Q4 2025","responsible_party":"NRF (IT and administration)"},
      {"step":7,"description":"Annual NRF Postgraduate Funding Report to Parliament: publish total bursary disbursements, completion rates by field and institution, industry co-funding receipts, skills market platform matches, and graduate employment outcomes 3 years post-degree; table in Portfolio Committee on Higher Education, Science and Innovation","timeline":"Annual from Q2 2026","responsible_party":"NRF / DHET"}
    ]',
    '18 months from review to reformed bursary system and platform launch (Q1 2025 – Q2 2026); full 5-year co-funding programme from 2026',
    'NRF bursary budget increase R400 million/year (40% uplift on current R1 billion bursary budget); platform development R15 million (capital); industry co-funding programme target R200 million/year in matching contributions; total public cost increase R400 million/year',
    'No new primary legislation required; NRF Act 23 of 1998 provides sufficient authority; bursary value increases and co-funding framework are administrative decisions within NRF Board authority; MTEF budget increase requires National Treasury approval',
    'NRF bursary value increases are within the NRF Board''s administrative authority under the NRF Act — no legislative process required. The industry co-funding framework is a contractual arrangement between NRF and private sector partners. The Skills Market Platform is an NRF digital infrastructure investment requiring PFMA-compliant procurement. The MTEF budget increase of R400 million/year requires National Treasury approval in the annual budget process.',
    'DHET, NRF, and the university sector have all publicly called for bursary value increases. Industry partners (Minerals Council, PIASA) have expressed interest in co-funding arrangements to address skills pipeline shortages. National Treasury resistance to increased NRF allocation is the primary constraint — the ROI modelling and industry co-funding match requirement are designed to address Treasury''s value-for-money concerns.',
    'Australia''s Research Training Program (ATP) stipends (AUD 32,000/year, CPI-indexed) provide the benchmark for bursary adequacy. Germany''s DAAD-Industry scholarship programme (co-funded by BASF, Siemens, and Bayer for specific research priorities) is the direct model for NRF''s Industry Co-funding Partnership Programme. The UK''s EPSRC Industrial CASE studentships (co-funded by UKRI and industry at GBP 19,000 base + GBP 6,000 industry top-up) provide the IP licensing and internship structure that NRF''s co-funding programme replicates.'
);

INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    73,
    'South African agricultural R&D is fragmented across the Agricultural Research Council (ARC, 15 research institutes, R2 billion budget), 26 universities, and a large but uncoordinated private sector. The result is duplicated effort, poor technology transfer to smallholder farmers, and underinvestment in priority areas — drought-resistant crop varieties, precision farming, and food processing. An Agri-Tech Innovation Cluster would consolidate R&D coordination, co-locate technology demonstrators near farming communities, and link with the SA Innovation Fund and TIA sector desk for startup support. Targets: 20% reduction in post-harvest losses by 2030 (from current ~30%) and 50 Agri-tech startups established by 2030.',
    '[
      {"step":1,"description":"DALRRD and DSIT co-commission a national agri-tech R&D mapping exercise: inventory all ARC, university, and private sector agri-tech R&D programmes; identify duplication, capability gaps in drought resistance and precision farming, and technology transfer bottlenecks; publish findings as the South African Agri-Tech R&D Landscape Report","timeline":"Q1-Q2 2025","responsible_party":"Department of Agriculture, Land Reform and Rural Development (DALRRD) / DSIT / ARC"},
      {"step":2,"description":"Establish the SA Agri-Tech Innovation Cluster governance structure: a Cluster Management Committee co-chaired by DALRRD and DSIT with ARC CEO, three university representatives (Stellenbosch, Free State, UKZN — centres of agri-tech excellence), AgriSA, the National African Farmers Union (NAFU), and private sector R&D representatives; Cluster secretariat hosted by ARC Infruitec-Nietvoorbij institute","timeline":"Q2-Q3 2025","responsible_party":"DALRRD / DSIT / ARC"},
      {"step":3,"description":"Launch the Drought-Resistant Crop R&D Programme: R600 million over 5 years to accelerate breeding programmes for drought-tolerant maize, sorghum, and cowpea varieties using marker-assisted selection and CRISPR gene editing (within SANS regulatory framework); target 10 new registered crop varieties by 2030; partner with CGIAR centres (CIMMYT, IITA) for germplasm access","timeline":"Q3 2025-Q4 2030","responsible_party":"ARC Plant Protection Research Institute / Stellenbosch University / CGIAR"},
      {"step":4,"description":"Establish precision farming technology demonstrators: five agri-tech demonstration hubs (Limpopo — subtropical, Free State — grain, Western Cape — horticulture, KwaZulu-Natal — sugarcane, Eastern Cape — livestock) integrating IoT soil sensors, drone-based crop monitoring, AI yield prediction models, and variable-rate application systems; hubs open to smallholder and commercial farmers for training","timeline":"Q4 2025-Q4 2027","responsible_party":"ARC / TIA (co-funding) / DALRRD provincial offices"},
      {"step":5,"description":"Launch the Agri-Tech Startup Accelerator: TIA Agri-Tech sector desk (from ID 66 reform) to fund 10 agri-tech startups per year through R5 million seed grants plus NRF-matched commercialisation support; SEDA to provide business development support; target 50 startups by 2030 with focus on post-harvest technology, cold chain logistics, and digital farm management platforms","timeline":"Q1 2026 (first cohort)","responsible_party":"TIA / NRF / SEDA"},
      {"step":6,"description":"Develop a national post-harvest loss reduction strategy: DALRRD to publish a Post-Harvest Loss Action Plan mapping the value chains with highest losses (vegetables 40%, fruit 35%, grain 15%); invest R400 million in rural cold chain infrastructure (community cold rooms, mobile refrigeration) through NARYSEC and RAADF programmes; partner with the FAO''s Save Food initiative","timeline":"Q2 2025 (strategy), Q1 2026-Q4 2029 (investment)","responsible_party":"DALRRD / dtic (cold chain) / NARYSEC"},
      {"step":7,"description":"Annual Agri-Tech Cluster Report: publish R&D investment by programme, new crop variety registrations, precision farming hectares covered, startup cohort outcomes, and post-harvest loss estimates by commodity; table in Portfolio Committee on Agriculture, Land Reform and Rural Development; use Stats SA General Household Survey data to track smallholder adoption of new technologies","timeline":"Annual from Q2 2026","responsible_party":"ARC / DALRRD / DSIT"}
    ]',
    '5-year programme 2025-2030; demonstration hubs operational by 2027; 20% post-harvest loss reduction and 50 startups by 2030',
    'Total programme R1.6 billion over 5 years: drought-resistant crop R&D R600 million, precision farming hubs R400 million, cold chain infrastructure R400 million, startup accelerator R200 million; funded across DALRRD, DSIT, ARC, and TIA budgets with private sector co-investment target R400 million',
    'No new primary legislation required; Plant Breeders Rights Act 15 of 1976 covers crop variety registration; Genetically Modified Organisms Act 15 of 1997 and SANS 10371 govern CRISPR applications; Agricultural Research Act 86 of 1990 governs ARC mandate expansion; PFMA governs cluster co-funding structures',
    'The Cluster Management Committee is an administrative coordination structure within existing DALRRD and DSIT mandates — no legislation required. CRISPR crop variety development operates within the GMO Act framework administered by DAFF — no legislative amendment required for marker-assisted selection; gene editing applications require DAFF regulatory determination on a case-by-case basis. Cold chain infrastructure investment falls within existing NARYSEC and RAADF programme authorities.',
    'Broad support from AgriSA, NAFU, and the agricultural university sector. DALRRD''s post-harvest loss focus aligns with food security commitments. The gene editing (CRISPR) component may face civil society objection from GMO opponents, but SA''s regulatory framework allows case-by-case assessment. Smallholder farmer organisations (NAFU, AFASA) are key political constituency — the demonstration hubs and startup accelerator must have explicit smallholder inclusion targets.',
    'Israel''s Volcani Centre model (government agri-tech R&D institute linked to regional demonstration farms) is the global benchmark for state-led agri-tech innovation with commercial uptake. The Netherlands'' Wageningen University and Research cluster (linking university, government institutes, and 1,200 companies in Food Valley) provides the cluster governance model. Kenya''s iHub and subsequent agri-tech ecosystem demonstrates that a focused startup accelerator can generate 50+ agri-tech companies within 5 years in an African context.'
);

INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    74,
    'The South African National Space Agency (SANSA) manages SA''s Earth observation and space science programme, including the legacy Sumbandila satellite (now decommissioned) and ground station infrastructure at Hartebeesthoek. SA''s participation in the Square Kilometre Array (SKA) creates a unique data economy opportunity that is currently underleveraged commercially. A commercialisation strategy covering Earth observation data licensing, a public-private partnership for the ZA-Cube small satellite series, and SKA data commercialisation would generate revenue to fund next-generation space science while positioning SA as an African space economy hub.',
    '[
      {"step":1,"description":"DSIT and SANSA commission a space economy commercial opportunity assessment: map all SANSA Earth observation data assets (historical archive, international satellite data access agreements), quantify the addressable market for commercial data licensing (agriculture, mining, urban planning, insurance), and assess South Africa''s comparative advantage in the SKA data economy; benchmark against Kenya''s Taifa-1 satellite and Nigeria''s NigeriaSat programme","timeline":"Q1-Q2 2025","responsible_party":"SANSA / DSIT / commercial consultant"},
      {"step":2,"description":"Develop the SANSA Earth Observation Data Licensing Framework: publish a data licensing policy covering tiered access (free for academic use, commercial licence for value-added applications, government discount rate for public sector users); establish pricing schedule benchmarked against ESA Copernicus Data Space and Planet Labs commercial data rates; deploy a digital data portal for licence applications","timeline":"Q2-Q4 2025","responsible_party":"SANSA / DSIT / CIPC (IP licensing template)"},
      {"step":3,"description":"Launch the ZA-Cube Small Satellite Public-Private Partnership: issue an open tender for a commercial satellite manufacturer to build 3 ZA-Cube satellites (12U-16U CubeSat class, optical and SAR payloads) under a design-build-operate-transfer model; SANSA provides spectrum allocation, ground station access, and R150 million co-funding; private partner retains commercial data revenue sharing rights for 5 years","timeline":"Q3 2025-Q4 2028 (procurement to launch)","responsible_party":"SANSA / DSIT / South African Air Force (SAAF) spectrum coordination"},
      {"step":4,"description":"Establish a SKA Data Economy Programme: in partnership with the SKA Organisation (now SKAO) and the Inter-University Institute for Data Intensive Astronomy (IDIA), develop commercial applications for SKA precursor data (MeerKAT, HIRAX); target applications in AI/ML algorithm licensing, radio frequency interference detection services for telecoms, and climate modelling datasets; revenue shared 50/50 between SANSA and participating university consortium","timeline":"Q1 2026","responsible_party":"SANSA / IDIA (UCT) / SARAO / DSIT"},
      {"step":5,"description":"Develop an African Space Data Hub at Hartebeesthoek: leverage SANSA''s ground station infrastructure (26-metre dish, fibre connectivity) to offer satellite telemetry, tracking, and command (TT&C) services to African space agencies (Kenya, Ethiopia, Nigeria, Rwanda); offer ground station as a service at commercial rates; target 5 African agency service agreements by 2027","timeline":"Q2 2025-Q4 2026","responsible_party":"SANSA / DIRCO (AU Space Programme liaison)"},
      {"step":6,"description":"Establish a SANSA Commercial Revenue Retention Fund: amend the South African National Space Agency Act 36 of 2008 to allow SANSA to retain commercial licensing and service revenues for reinvestment in space infrastructure, rather than returning to Treasury; target revenue retention of R100 million/year by 2030 to fund next-generation satellite development","timeline":"Q2-Q4 2025 (legislative process)","responsible_party":"DSIT / SANSA / National Treasury"},
      {"step":7,"description":"Annual SA Space Economy Report: SANSA publishes space economy GDP contribution, licensing revenues, satellite data users, job creation (direct and indirect), and international partnership outcomes; align with OECD Space Economy at a Glance methodology; table in Portfolio Committee on Higher Education, Science and Innovation","timeline":"Annual from Q2 2026","responsible_party":"SANSA / DSIT / Stats SA"}
    ]',
    '5-year commercialisation programme 2025-2030; ZA-Cube launch by 2028; African Space Data Hub operational 2026; commercial revenue target R100 million/year by 2030',
    'ZA-Cube PPP: SANSA co-funding R150 million (private partner provides balance); ground station upgrade R50 million; SKA Data Economy Programme R30 million; SANSA data portal R20 million; total public investment R250 million over 5 years; commercial revenue target R100 million/year by 2030',
    'SANSA Act 36 of 2008 amendment required for commercial revenue retention; Space Affairs Act 84 of 1993 may require update to clarify commercial satellite licensing framework; Electronic Communications Act 36 of 2005 governs spectrum allocation for ZA-Cube programme',
    'The SANSA Act amendment to allow commercial revenue retention requires a bill tabled by the Minister of Science, Innovation and Technology and processed through the Portfolio Committee on Higher Education, Science and Innovation. The Space Affairs Act review is a longer-term process — DSIT has committed to a comprehensive Space Policy White Paper (announced 2024) that would address the legislative framework. ZA-Cube PPP procurement follows standard PFMA-compliant tender procedures.',
    'Moderate-to-strong support: SANSA leadership and DSIT have explicitly committed to space economy commercialisation as a priority. The ZA-Cube PPP model will attract commercial interest from established small satellite manufacturers (Thales Alenia, Surrey Satellite Technology, EnduroSat). Budget constraint is the primary risk — National Treasury has historically underfunded SANSA relative to peers. The African Space Data Hub leverages SA''s existing infrastructure advantage and has AU backing through the African Space Policy and Strategy (2016).',
    'ESA''s Copernicus programme (EUR 8 billion investment, free-and-open data policy with commercial value-added resellers) generated EUR 53 billion in downstream economic value by 2022 — the benchmark for Earth observation data economy returns. Luxembourg''s space economy commercialisation strategy (SpaceResources.lu) demonstrates how a small country can position itself as a space economy hub through targeted PPP and regulatory innovation. Kenya''s Taifa-1 satellite (2023, launched on SpaceX Transporter-7) provides the nearest African model for a small satellite PPP — SA''s ZA-Cube programme would be significantly larger in scope.'
);

INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    75,
    'South Africa is a megadiverse country with globally significant indigenous biological resources and traditional knowledge (TK). As a signatory to the Convention on Biological Diversity (CBD) and the Nagoya Protocol on Access and Benefit-Sharing (ratified 2013), SA is obligated to operationalise an access and benefit-sharing (ABS) system for traditional knowledge and genetic resources. The Traditional Knowledge, Genetic Resources and Expressions of Folklore Bill (tabled 2023 by DTIC) — combined with existing ABS obligations under the Biodiversity Act 10 of 2004 — creates a framework, but CIPC and DTIC have not yet operationalised the ABS register, bioprospecting permit processing remains slow, and communities lack capacity to negotiate benefit-sharing agreements. Full operationalisation is both a legal obligation and an economic development opportunity.',
    '[
      {"step":1,"description":"DTIC and CIPC commission a gap analysis of existing ABS frameworks: map all bioprospecting permits issued under Biodiversity Act Section 82 (DFFE administers), existing benefit-sharing agreements, and CIPC''s current TK/folklore registration system; identify processing backlogs, community notification failures, and interface problems between CIPC, DFFE, and DTIC systems; produce a consolidated ABS System Operationalisation Plan","timeline":"Q1-Q2 2025","responsible_party":"DTIC / CIPC / DFFE (biodiversity branch)"},
      {"step":2,"description":"Enact the Traditional Knowledge, Genetic Resources and Expressions of Folklore Act: complete parliamentary process for the Bill tabled in 2023; ensure the Act establishes: a single National ABS Register hosted by CIPC; mandatory prior informed consent (PIC) protocols for access to TK; standard benefit-sharing agreement templates; DTIC as the lead ABS authority with DFFE for genetic resources and CIPC for IP registration","timeline":"Q2-Q4 2025 (parliamentary process)","responsible_party":"DTIC / CIPC / Parliament (Portfolio Committee on Trade, Industry and Competition)"},
      {"step":3,"description":"Build the National ABS Register: CIPC to develop and host a digital register of TK holders, indigenous community IP assets, existing benefit-sharing agreements, and bioprospecting permits; integrate with DFFE''s bioprospecting permit system and NIPMO''s IP register; publish register publicly with community consent; target 500 registered TK entries by 2027","timeline":"Q3 2025-Q2 2026 (development), Q2 2026 (launch)","responsible_party":"CIPC / DTIC / DFFE"},
      {"step":4,"description":"Establish Community Capacity Support Programme: DTIC partners with Legal Aid SA, the South African San Institute, ACAT (Association for Cultural Advancement and Training), and the DSI''s indigenous knowledge programme to provide free legal assistance to indigenous communities in PIC negotiations and benefit-sharing agreement drafting; fund 20 community liaison officers stationed in biodiversity-rich provinces (KZN, EC, Limpopo, Western Cape, Northern Cape)","timeline":"Q4 2025-Q4 2027","responsible_party":"DTIC / Legal Aid SA / DSI"},
      {"step":5,"description":"Develop standard benefit-sharing agreement templates: DTIC and CIPC to publish a library of modular standard benefit-sharing agreement templates (financial royalties, research partnerships, capacity building components, community development fund contributions) legally compliant with the Nagoya Protocol; templates reviewed by the ABS Compliance Committee and published for free community use","timeline":"Q2-Q4 2025","responsible_party":"DTIC / CIPC / ABS legal experts"},
      {"step":6,"description":"Operationalise the ABS Compliance Monitoring System: CIPC establishes a compliance unit to monitor that users of TK and genetic resources registered under the ABS system are meeting benefit-sharing obligations; introduce an annual compliance certificate requirement for commercial users; refer non-compliance to the SA Police Service''s commercial crimes unit or DFFE for Biodiversity Act enforcement","timeline":"Q1-Q2 2026","responsible_party":"CIPC / DTIC / DFFE / SAPS"},
      {"step":7,"description":"Annual ABS Programme Report to Parliament: DTIC and CIPC publish the number of registered TK entries, bioprospecting permits processed, benefit-sharing agreements concluded, royalty revenues distributed to communities, and compliance enforcement actions; report reviewed by Portfolio Committee on Trade, Industry and Competition and Portfolio Committee on Forestry, Fisheries and the Environment; include gender disaggregation of community benefits","timeline":"Annual from Q2 2026","responsible_party":"DTIC / CIPC / DFFE"}
    ]',
    '2 years to full ABS system operationalisation (Q1 2025 – Q2 2027); TK Act enacted by Q4 2025; National ABS Register live Q2 2026',
    'CIPC ABS Register development R25 million (capital); Community Capacity Support Programme R40 million/year; standard template development R5 million; compliance unit R10 million/year; total public cost R100 million over 5 years; benefit-sharing revenues to communities estimated R50-200 million/year once system is operational',
    'Traditional Knowledge, Genetic Resources and Expressions of Folklore Bill (2023) must be enacted; Biodiversity Act 10 of 2004 Section 82 regulations may require updating to interface with the new TK Act; Intellectual Property Laws Amendment Act 28 of 2013 (which introduced TK provisions into IP laws) requires integration with the new framework',
    'The TK Bill is currently before Parliament''s Portfolio Committee on Trade, Industry and Competition. The Bill''s passage requires coordination between DTIC (TK and commercial IP) and DFFE (genetic resources and biodiversity). The Nagoya Protocol ratification creates a binding international obligation — the Constitutional Court may rule against SA if the system remains inoperational. The IP Laws Amendment Act provisions need harmonisation with the new Bill to avoid contradictory frameworks.',
    'The San and Khoe communities and the South African San Institute are strong advocates for the ABS framework and have engaged directly with DTIC and CIPC. The pharmaceutical and cosmetics industries (PIASA, CTFA) support a clear ABS framework — legal certainty reduces their compliance risk. Some industry actors have lobbied for lighter-touch requirements; community organisations insist on strong PIC and fair royalty standards. The DA supports IP clarity; the ANC''s rural development constituency supports community benefit-sharing. EFF supports strong community rights but may propose nationalisation of genetic resources, which would be incompatible with the Nagoya Protocol.',
    'The Nagoya Protocol''s ABS framework has been operationalised most effectively in Brazil (SISGEN system — national online ABS register with 30,000+ entries) and Switzerland (ABS Clearing-House integrated with WIPO IP system). The Maori traditional knowledge protection framework in New Zealand (under the Patents Act 2013 Section 15 exclusion and the Wai 262 treaty claim framework) provides an indigenous rights model for PIC requirements. The Rooibos benefit-sharing agreement (2019, between South African Rooibos industry and San and Khoe communities — USD 1.65 million/year) is SA''s own proof of concept for the commercial value of the ABS framework.'
);

COMMIT;
